
CREATE PROCEDURE AX2009.usp_Merge_SALESLINE_OrdiniCliente_Riga
AS
BEGIN
SET NOCOUNT ON;

IF OBJECT_ID('AX2009.SALESLINE_OrdiniCliente_Riga', N'U') IS NULL
BEGIN
    EXEC AX2009.usp_Create_SALESLINE_OrdiniCliente_Riga;
    EXEC AX2009.usp_AddIndexes_SALESLINE_OrdiniCliente_Riga;
END;

MERGE INTO AX2009.SALESLINE_OrdiniCliente_Riga AS TGT
USING AX2009.SALESLINE_OrdiniCliente_RigaView (nolock) AS SRC
ON SRC.DATAAREAID = TGT.DATAAREAID AND SRC.SALESID = TGT.SALESID AND SRC.NPOLINENUM = TGT.NPOLINENUM AND SRC.RECID = TGT.RECID
WHEN MATCHED AND (TGT.ITEMID <> SRC.ITEMID OR TGT.SALESSTATUS <> SRC.SALESSTATUS OR TGT.NAME <> SRC.NAME OR TGT.EXTERNALITEMID <> SRC.EXTERNALITEMID OR TGT.DIMENSION <> SRC.DIMENSION OR TGT.DIMENSION2_ <> SRC.DIMENSION2_ OR TGT.DIMENSION3_ <> SRC.DIMENSION3_ OR TGT.INVENTTRANSID <> SRC.INVENTTRANSID OR TGT.UNDERDELIVERYPCT <> SRC.UNDERDELIVERYPCT OR TGT.OVERDELIVERYPCT <> SRC.OVERDELIVERYPCT OR TGT.INVENTREFTRANSID <> SRC.INVENTREFTRANSID OR TGT.INVENTREFTYPE <> SRC.INVENTREFTYPE OR TGT.INVENTREFID <> SRC.INVENTREFID OR TGT.INTERCOMPANYORIGIN <> SRC.INTERCOMPANYORIGIN OR TGT.INVENTDIMID <> SRC.INVENTDIMID OR TGT.CUSTOMERLINENUM <> SRC.CUSTOMERLINENUM OR TGT.SHIPPINGDATEREQUESTED <> SRC.SHIPPINGDATEREQUESTED OR TGT.SHIPPINGDATECONFIRMED <> SRC.SHIPPINGDATECONFIRMED OR TGT.CREATEDDATETIME <> SRC.CREATEDDATETIME OR TGT.NPODLVREASON <> SRC.NPODLVREASON OR TGT.NPOFINISHINGID <> SRC.NPOFINISHINGID OR TGT.NPOOTHERINFO <> SRC.NPOOTHERINFO OR TGT.NPOPHYSICALSTATEALLOYID <> SRC.NPOPHYSICALSTATEALLOYID OR TGT.NPOLENGTH <> SRC.NPOLENGTH OR TGT.NPOALLOYID <> SRC.NPOALLOYID OR TGT.NPOPBAINTERCOMPANYBOMITEMID <> SRC.NPOPBAINTERCOMPANYBOMITEMID OR TGT.NPOCONTRACTWORKTRANSID <> SRC.NPOCONTRACTWORKTRANSID OR TGT.NPOREVENUEREFTRANSID <> SRC.NPOREVENUEREFTRANSID OR TGT.NPOREVENUESALESLINE <> SRC.NPOREVENUESALESLINE OR TGT.NPOWRKCTRGROUPID <> SRC.NPOWRKCTRGROUPID OR TGT.NPOWRKCTRCHARGES <> SRC.NPOWRKCTRCHARGES OR TGT.NPOINTERCOMPANYORIGINALSALESID <> SRC.NPOINTERCOMPANYORIGINALSALESID OR TGT.NPOINTERCOMPANYORIGINALCU30041 <> SRC.NPOINTERCOMPANYORIGINALCU30041 OR TGT.NPOINTERCOMPANYORIGINALIN30042 <> SRC.NPOINTERCOMPANYORIGINALIN30042 OR TGT.DIMENSION4_ <> SRC.DIMENSION4_ OR TGT.DIMENSION5_ <> SRC.DIMENSION5_ OR TGT.DIMENSION6_ <> SRC.DIMENSION6_ OR TGT.NCEPROFILEFINISHWEIGHTCHECKED <> SRC.NCEPROFILEFINISHWEIGHTCHECKED OR TGT.NCEREQUISITIONTYPE <> SRC.NCEREQUISITIONTYPE OR TGT.NPOWRKCTRREFPURCHID <> SRC.NPOWRKCTRREFPURCHID OR TGT.SALESUNIT <> SRC.SALESUNIT OR TGT.SALESQTY <> SRC.SALESQTY OR TGT.NPOSALESUNIT <> SRC.NPOSALESUNIT OR TGT.NPOSALESQTY <> SRC.NPOSALESQTY OR TGT.QTYORDERED <> SRC.QTYORDERED OR TGT.REMAINSALESPHYSICAL <> SRC.REMAINSALESPHYSICAL OR TGT.REMAININVENTPHYSICAL <> SRC.REMAININVENTPHYSICAL OR TGT.REMAINSALESFINANCIAL <> SRC.REMAINSALESFINANCIAL OR TGT.CURRENCYCODE <> SRC.CURRENCYCODE OR TGT.LINEAMOUNT <> SRC.LINEAMOUNT OR TGT.SALESPRICE <> SRC.SALESPRICE OR TGT.PRICEUNIT <> SRC.PRICEUNIT OR TGT.LINEPERCENT <> SRC.LINEPERCENT OR TGT.LINEDISC <> SRC.LINEDISC)
  THEN UPDATE SET TGT.ITEMID = SRC.ITEMID, TGT.SALESSTATUS = SRC.SALESSTATUS, TGT.NAME = SRC.NAME, TGT.EXTERNALITEMID = SRC.EXTERNALITEMID, TGT.DIMENSION = SRC.DIMENSION, TGT.DIMENSION2_ = SRC.DIMENSION2_, TGT.DIMENSION3_ = SRC.DIMENSION3_, TGT.INVENTTRANSID = SRC.INVENTTRANSID, TGT.UNDERDELIVERYPCT = SRC.UNDERDELIVERYPCT, TGT.OVERDELIVERYPCT = SRC.OVERDELIVERYPCT, TGT.INVENTREFTRANSID = SRC.INVENTREFTRANSID, TGT.INVENTREFTYPE = SRC.INVENTREFTYPE, TGT.INVENTREFID = SRC.INVENTREFID, TGT.INTERCOMPANYORIGIN = SRC.INTERCOMPANYORIGIN, TGT.INVENTDIMID = SRC.INVENTDIMID, TGT.CUSTOMERLINENUM = SRC.CUSTOMERLINENUM, TGT.SHIPPINGDATEREQUESTED = SRC.SHIPPINGDATEREQUESTED, TGT.SHIPPINGDATECONFIRMED = SRC.SHIPPINGDATECONFIRMED, TGT.CREATEDDATETIME = SRC.CREATEDDATETIME, TGT.NPODLVREASON = SRC.NPODLVREASON, TGT.NPOFINISHINGID = SRC.NPOFINISHINGID, TGT.NPOOTHERINFO = SRC.NPOOTHERINFO, TGT.NPOPHYSICALSTATEALLOYID = SRC.NPOPHYSICALSTATEALLOYID, TGT.NPOLENGTH = SRC.NPOLENGTH, TGT.NPOALLOYID = SRC.NPOALLOYID, TGT.NPOPBAINTERCOMPANYBOMITEMID = SRC.NPOPBAINTERCOMPANYBOMITEMID, TGT.NPOCONTRACTWORKTRANSID = SRC.NPOCONTRACTWORKTRANSID, TGT.NPOREVENUEREFTRANSID = SRC.NPOREVENUEREFTRANSID, TGT.NPOREVENUESALESLINE = SRC.NPOREVENUESALESLINE, TGT.NPOWRKCTRGROUPID = SRC.NPOWRKCTRGROUPID, TGT.NPOWRKCTRCHARGES = SRC.NPOWRKCTRCHARGES, TGT.NPOINTERCOMPANYORIGINALSALESID = SRC.NPOINTERCOMPANYORIGINALSALESID, TGT.NPOINTERCOMPANYORIGINALCU30041 = SRC.NPOINTERCOMPANYORIGINALCU30041, TGT.NPOINTERCOMPANYORIGINALIN30042 = SRC.NPOINTERCOMPANYORIGINALIN30042, TGT.DIMENSION4_ = SRC.DIMENSION4_, TGT.DIMENSION5_ = SRC.DIMENSION5_, TGT.DIMENSION6_ = SRC.DIMENSION6_, TGT.NCEPROFILEFINISHWEIGHTCHECKED = SRC.NCEPROFILEFINISHWEIGHTCHECKED, TGT.NCEREQUISITIONTYPE = SRC.NCEREQUISITIONTYPE, TGT.NPOWRKCTRREFPURCHID = SRC.NPOWRKCTRREFPURCHID, TGT.SALESUNIT = SRC.SALESUNIT, TGT.SALESQTY = SRC.SALESQTY, TGT.NPOSALESUNIT = SRC.NPOSALESUNIT, TGT.NPOSALESQTY = SRC.NPOSALESQTY, TGT.QTYORDERED = SRC.QTYORDERED, TGT.REMAINSALESPHYSICAL = SRC.REMAINSALESPHYSICAL, TGT.REMAININVENTPHYSICAL = SRC.REMAININVENTPHYSICAL, TGT.REMAINSALESFINANCIAL = SRC.REMAINSALESFINANCIAL, TGT.CURRENCYCODE = SRC.CURRENCYCODE, TGT.LINEAMOUNT = SRC.LINEAMOUNT, TGT.SALESPRICE = SRC.SALESPRICE, TGT.PRICEUNIT = SRC.PRICEUNIT, TGT.LINEPERCENT = SRC.LINEPERCENT, TGT.LINEDISC = SRC.LINEDISC
WHEN NOT MATCHED
  THEN INSERT VALUES (DATAAREAID, SALESID, NPOLINENUM, RECID, ITEMID, SALESSTATUS, NAME, EXTERNALITEMID, DIMENSION, DIMENSION2_, DIMENSION3_, INVENTTRANSID, UNDERDELIVERYPCT, OVERDELIVERYPCT, INVENTREFTRANSID, INVENTREFTYPE, INVENTREFID, INTERCOMPANYORIGIN, INVENTDIMID, CUSTOMERLINENUM, SHIPPINGDATEREQUESTED, SHIPPINGDATECONFIRMED, CREATEDDATETIME, NPODLVREASON, NPOFINISHINGID, NPOOTHERINFO, NPOPHYSICALSTATEALLOYID, NPOLENGTH, NPOALLOYID, NPOPBAINTERCOMPANYBOMITEMID, NPOCONTRACTWORKTRANSID, NPOREVENUEREFTRANSID, NPOREVENUESALESLINE, NPOWRKCTRGROUPID, NPOWRKCTRCHARGES, NPOINTERCOMPANYORIGINALSALESID, NPOINTERCOMPANYORIGINALCU30041, NPOINTERCOMPANYORIGINALIN30042, DIMENSION4_, DIMENSION5_, DIMENSION6_, NCEPROFILEFINISHWEIGHTCHECKED, NCEREQUISITIONTYPE, NPOWRKCTRREFPURCHID, SALESUNIT, SALESQTY, NPOSALESUNIT, NPOSALESQTY, QTYORDERED, REMAINSALESPHYSICAL, REMAININVENTPHYSICAL, REMAINSALESFINANCIAL, CURRENCYCODE, LINEAMOUNT, SALESPRICE, PRICEUNIT, LINEPERCENT, LINEDISC)
WHEN NOT MATCHED BY SOURCE
  THEN DELETE
OUTPUT
    CURRENT_TIMESTAMP AS merge_datetime,
    $action AS merge_action,
    'AX2009.SALESLINE_OrdiniCliente_Riga' AS full_olap_table_name,
    'DATAAREAID = ' + CAST(COALESCE(inserted.DATAAREAID, deleted.DATAAREAID) AS NVARCHAR) + ' - ' + 'SALESID = ' + CAST(COALESCE(inserted.SALESID, deleted.SALESID) AS NVARCHAR) + ' - ' + 'NPOLINENUM = ' + CAST(COALESCE(inserted.NPOLINENUM, deleted.NPOLINENUM) AS NVARCHAR) + ' - ' + 'RECID = ' + CAST(COALESCE(inserted.RECID, deleted.RECID) AS NVARCHAR) AS primary_key_description
INTO audit.merge_log_details;

END;
GO

